from dataclasses import dataclass, field
from typing import Optional, List, Dict, Any, Union
from enum import Enum
from pathlib import Path
import logging
import base64
import json

from openai import OpenAI
import anthropic

class ImageSource(Enum):
    URL = "url"
    FILE = "file"
    BASE64 = "base64"

@dataclass
class VisionConfig:
    """Configuration for vision service."""
    model: str = "gpt-4o"
    max_image_size_mb: int = 20
    detail: str = "auto"  # "low", "high", "auto"
    max_retries: int = 3
    timeout: int = 60
    temperature: float = 0.0  # Zero for deterministic extraction

@dataclass
class VisionResult:
    """Result from vision analysis."""
    success: bool
    content: Optional[Union[str, dict]] = None
    error: Optional[str] = None
    usage: Dict[str, int] = field(default_factory=dict)
    model: Optional[str] = None

class VisionService:
    """Production-grade vision analysis service."""

    MEDIA_TYPES = {
        ".jpg": "image/jpeg",
        ".jpeg": "image/jpeg",
        ".png": "image/png",
        ".gif": "image/gif",
        ".webp": "image/webp"
    }

    def __init__(self, config: Optional[VisionConfig] = None):
        self.config = config or VisionConfig()
        self.client = OpenAI()
        self.logger = logging.getLogger(__name__)

    def analyze(
        self,
        image: Union[str, Path],
        prompt: str,
        source_type: ImageSource = ImageSource.FILE,
        structured_output: bool = False
    ) -> VisionResult:
        """Analyze image with error handling and retries."""
        try:
            image_content = self._prepare_image(image, source_type)

            messages = [{
                "role": "user",
                "content": [
                    {"type": "text", "text": prompt},
                    {
                        "type": "image_url",
                        "image_url": {
                            "url": image_content,
                            "detail": self.config.detail
                        }
                    }
                ]
            }]

            kwargs = {
                "model": self.config.model,
                "messages": messages,
                "timeout": self.config.timeout,
                "temperature": self.config.temperature
            }

            if structured_output:
                kwargs["response_format"] = {"type": "json_object"}

            last_error = None
            for attempt in range(self.config.max_retries):
                try:
                    response = self.client.chat.completions.create(**kwargs)
                    content = response.choices[0].message.content

                    return VisionResult(
                        success=True,
                        content=json.loads(content) if structured_output else content,
                        usage={
                            "prompt_tokens": response.usage.prompt_tokens,
                            "completion_tokens": response.usage.completion_tokens
                        },
                        model=response.model
                    )
                except Exception as e:
                    last_error = e
                    self.logger.warning(f"Attempt {attempt + 1}/{self.config.max_retries} failed: {e}")

            raise last_error

        except Exception as e:
            self.logger.error(f"Vision analysis failed: {e}")
            return VisionResult(success=False, error=str(e))

    def _prepare_image(self, image: Union[str, Path], source_type: ImageSource) -> str:
        if source_type == ImageSource.URL:
            return str(image)

        if source_type == ImageSource.BASE64:
            return f"data:image/jpeg;base64,{image}"

        path = Path(image)
        if not path.exists():
            raise FileNotFoundError(f"Image not found: {path}")

        size_mb = path.stat().st_size / (1024 * 1024)
        if size_mb > self.config.max_image_size_mb:
            raise ValueError(f"Image too large: {size_mb:.1f}MB (max: {self.config.max_image_size_mb}MB)")

        with open(path, "rb") as f:
            data = base64.b64encode(f.read()).decode()

        media_type = self.MEDIA_TYPES.get(path.suffix.lower(), "image/jpeg")
        return f"data:{media_type};base64,{data}"

    def batch_analyze(
        self,
        images: List[Union[str, Path]],
        prompt: str,
        source_type: ImageSource = ImageSource.FILE
    ) -> List[VisionResult]:
        """Analyze multiple images sequentially."""
        return [self.analyze(img, prompt, source_type) for img in images]

class MultiProviderVisionService:
    """Vision service with multi-provider fallback."""

    def __init__(self):
        self.openai = OpenAI()
        self.anthropic = anthropic.Anthropic()

    def analyze(self, image_path: str, prompt: str) -> Dict[str, Any]:
        """Analyze with fallback between providers."""
        try:
            result = self._analyze_openai(image_path, prompt)
            return {"success": True, "provider": "openai", "content": result}
        except Exception as e:
            pass  # log e

        try:
            result = self._analyze_claude(image_path, prompt)
            return {"success": True, "provider": "claude", "content": result}
        except Exception as e:
            pass  # log e

        return {"success": False, "error": "All providers failed"}

    def _analyze_openai(self, image_path: str, prompt: str) -> str:
        with open(image_path, "rb") as f:
            image_data = base64.b64encode(f.read()).decode()
        response = self.openai.chat.completions.create(
            model="gpt-4o",
            messages=[{
                "role": "user",
                "content": [
                    {"type": "text", "text": prompt},
                    {"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{image_data}"}}
                ]
            }]
        )
        return response.choices[0].message.content

    def _analyze_claude(self, image_path: str, prompt: str) -> str:
        with open(image_path, "rb") as f:
            image_data = base64.b64encode(f.read()).decode()
        response = self.anthropic.messages.create(
            model="claude-sonnet-4-5-20250514",
            max_tokens=4096,
            messages=[{
                "role": "user",
                "content": [
                    {"type": "image", "source": {"type": "base64", "media_type": "image/jpeg", "data": image_data}},
                    {"type": "text", "text": prompt}
                ]
            }]
        )
        return response.content[0].text

import asyncio
from concurrent.futures import ThreadPoolExecutor

async def batch_analyze(image_paths: list, prompt: str, max_workers: int = 5) -> list:
    """Analyze multiple images concurrently."""

    def analyze_single(path: str) -> dict:
        from openai import OpenAI
        import base64
        client = OpenAI()
        try:
            with open(path, "rb") as f:
                image_data = base64.b64encode(f.read()).decode()
            response = client.chat.completions.create(
                model="gpt-4o",
                messages=[{
                    "role": "user",
                    "content": [
                        {"type": "text", "text": prompt},
                        {"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{image_data}"}}
                    ]
                }]
            )
            return {"path": path, "success": True, "content": response.choices[0].message.content}
        except Exception as e:
            return {"path": path, "success": False, "error": str(e)}

    loop = asyncio.get_event_loop()
    with ThreadPoolExecutor(max_workers=max_workers) as executor:
        tasks = [loop.run_in_executor(executor, analyze_single, path) for path in image_paths]
        results = await asyncio.gather(*tasks)
    return results
